'use client';

import { useEffect, useRef, useState } from 'react';
import WaveSurfer from 'wavesurfer.js';
import styles from './AudioPreview.module.scss';

interface AudioPreviewProps {
  audioSrc: string;
}

function formatTime(seconds: number): string {
  const m = Math.floor(seconds / 60);
  const s = Math.floor(seconds % 60);
  return `${m}:${s.toString().padStart(2, '0')}`;
}

function PlayIcon() {
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none" aria-hidden="true">
      <path d="M5 3.5L16.5 10 5 16.5V3.5Z" fill="currentColor" />
    </svg>
  );
}

function PauseIcon() {
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none" aria-hidden="true">
      <rect x="4" y="3" width="4" height="14" rx="1" fill="currentColor" />
      <rect x="12" y="3" width="4" height="14" rx="1" fill="currentColor" />
    </svg>
  );
}

export default function AudioPreview({ audioSrc }: AudioPreviewProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const wavesurferRef = useRef<WaveSurfer | null>(null);

  const [isPlaying, setIsPlaying] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [hasError, setHasError] = useState(false);

  useEffect(() => {
    if (!containerRef.current) return;

    const ws = WaveSurfer.create({
      container: containerRef.current,
      waveColor: 'rgba(255, 255, 255, 0.35)',
      progressColor: '#c97832',
      cursorColor: 'transparent',
      barWidth: 2,
      barGap: 2,
      barRadius: 2,
      height: 36,
      normalize: true,
      interact: true,
    });

    wavesurferRef.current = ws;

    ws.load(audioSrc);

    ws.on('ready', () => {
      setIsLoading(false);
      setDuration(ws.getDuration());
    });

    ws.on('play', () => setIsPlaying(true));
    ws.on('pause', () => setIsPlaying(false));

    ws.on('finish', () => {
      setIsPlaying(false);
      setCurrentTime(0);
      ws.seekTo(0);
    });

    ws.on('timeupdate', (time) => {
      setCurrentTime(time);
    });

    ws.on('error', () => {
      setHasError(true);
      setIsLoading(false);
    });

    return () => {
      ws.destroy();
    };
  }, [audioSrc]);

  function handlePlayPause() {
    wavesurferRef.current?.playPause();
  }

  return (
    <div className={styles['audio-preview']}>
      <button
        className={styles['audio-preview__play-btn']}
        onClick={handlePlayPause}
        aria-label={isPlaying ? 'Pause preview' : 'Play preview'}
        disabled={isLoading || hasError}
      >
        {isPlaying ? <PauseIcon /> : <PlayIcon />}
      </button>

      <div className={styles['audio-preview__waveform-area']}>
        {hasError ? (
          <p className={styles['audio-preview__error']}>Preview unavailable</p>
        ) : (
          <>
            <div
              ref={containerRef}
              className={`${styles['audio-preview__waveform']} ${isLoading ? styles['audio-preview__waveform--loading'] : ''}`}
            />
            <div className={styles['audio-preview__time']}>
              <span>{formatTime(currentTime)}</span>
              <span>{formatTime(duration)}</span>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
